1	type Cell = [x: number, y: number];
2	type CellKey = string;
3	
4	const toKey = (x: number, y: number): CellKey => `${x},${y}`;
5	
6	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1, 0],           [1, 0],
9	  [-1, 1],  [0, 1],  [1, 1],
10	];
11	
12	const isAliveNextGeneration = (neighborCount: number, isCurrentlyAlive: boolean): boolean =>
13	  neighborCount === 3 || (neighborCount === 2 && isCurrentlyAlive);
14	
15	export function nextGeneration(cells: Cell[]): Cell[] {
16	  const liveCells = new Set(cells.map(([x, y]) => toKey(x, y)));
17	  const candidates = new Map<CellKey, { cell: Cell; neighborCount: number }>();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const key = toKey(neighbor[0], neighbor[1]);
22	      const existing = candidates.get(key);
23	      candidates.set(key, {
24	        cell: neighbor,
25	        neighborCount: (existing?.neighborCount ?? 0) + 1,
26	      });
27	    }
28	  }
29	  const result: Cell[] = [];
30	  for (const [key, { cell, neighborCount }] of candidates) {
31	    if (isAliveNextGeneration(neighborCount, liveCells.has(key))) {
32	      result.push(cell);
33	    }
34	  }
35	  return result;
36	}
